/**
 * Shared institutional print/PDF layout for SMS Oriximiná.
 * All documents generated by the system use this template
 * to ensure consistent branding across screen, PDF, and print.
 * 
 * Supports dual logos (SMS + CER II), justified text, proper
 * margins (2.5cm), 1.5 line spacing, Arial font.
 */

import { supabase } from '@/integrations/supabase/client';
import logoSmsFallback from '@/assets/logo-sms-oriximina.jpeg';
import logoCerFallback from '@/assets/logo-cer-ii.png';

export interface DocumentConfig {
  logoEsquerda: string;
  logoDireita: string;
  linha1: string;
  linha2: string;
  rodapeTexto: string;
}

const DEFAULT_CONFIG: DocumentConfig = {
  logoEsquerda: '',
  logoDireita: '',
  linha1: 'SECRETARIA MUNICIPAL DE SAÚDE DE ORIXIMINÁ',
  linha2: 'CENTRO ESPECIALIZADO EM REABILITAÇÃO NÍVEL II',
  rodapeTexto: '',
};

let _cachedConfig: DocumentConfig | null = null;
let _cacheTimestamp = 0;
const CACHE_TTL = 60_000; // 1 min

export async function loadDocumentConfig(): Promise<DocumentConfig> {
  if (_cachedConfig && Date.now() - _cacheTimestamp < CACHE_TTL) return _cachedConfig;
  try {
    const { data } = await supabase
      .from('system_config')
      .select('configuracoes')
      .eq('id', 'default')
      .maybeSingle();
    const cfg = (data?.configuracoes as any)?.config_impressao;
    if (cfg) {
      _cachedConfig = {
        logoEsquerda: cfg.cabecalho?.logoEsquerda || cfg.cabecalho?.logoUrl || '',
        logoDireita: cfg.cabecalho?.logoDireita || '',
        linha1: cfg.cabecalho?.linha1 || DEFAULT_CONFIG.linha1,
        linha2: cfg.cabecalho?.linha2 || DEFAULT_CONFIG.linha2,
        rodapeTexto: cfg.rodapeTexto || '',
      };
    } else {
      _cachedConfig = { ...DEFAULT_CONFIG };
    }
  } catch {
    _cachedConfig = { ...DEFAULT_CONFIG };
  }
  _cacheTimestamp = Date.now();
  return _cachedConfig!;
}

/** Invalidate cached config (call after saving new config) */
export function invalidateDocumentConfigCache(): void {
  _cachedConfig = null;
  _cacheTimestamp = 0;
}

function resolveLogoUrl(configUrl: string, fallback: string): string {
  if (configUrl && configUrl.startsWith('http')) return configUrl;
  if (configUrl && configUrl.startsWith('/')) return configUrl;
  // Use bundled fallback
  if (fallback.startsWith('http') || fallback.startsWith('/')) return fallback;
  return fallback;
}

/** Standard institutional CSS shared across all documents */
